import{_ as a,o as t,c as r,ak as o}from"./chunks/framework.Dx0ZwfXr.js";const h=JSON.parse('{"title":"GatewayConfiguration","description":"","frontmatter":{},"headers":[],"relativePath":"api/reference/royalapps-community-rdp-winforms-configuration-connection-gatewayconfiguration.md","filePath":"api/reference/royalapps-community-rdp-winforms-configuration-connection-gatewayconfiguration.md"}'),s={name:"api/reference/royalapps-community-rdp-winforms-configuration-connection-gatewayconfiguration.md"};function n(i,e,d,c,l,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="gatewayconfiguration" tabindex="-1"><code>GatewayConfiguration</code> <a class="header-anchor" href="#gatewayconfiguration" aria-label="Permalink to “GatewayConfiguration”">​</a></h1><p>Remote Desktop Gateway configuration and settings.</p><h2 id="type" tabindex="-1">Type <a class="header-anchor" href="#type" aria-label="Permalink to “Type”">​</a></h2><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RoyalApps.Community.Rdp.WinForms.Configuration.Connection.GatewayConfiguration</span></span></code></pre></div><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to “Properties”">​</a></h2><h3 id="gatewaycredsharing-bool-↗" tabindex="-1"><code>GatewayCredSharing</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings2-gatewaycredsharing" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewaycredsharing-bool-↗" aria-label="Permalink to “GatewayCredSharing (bool) ↗”">​</a></h3><p>Specifies or retrieves the setting for whether the Remote Desktop Gateway (RD Gateway) credential sharing feature is enabled. When the feature is enabled, the Remote Desktop ActiveX control tries to use the same credentials to authenticate to the Remote Desktop Session Host (RD Session Host) server and to the RD Gateway server. Support: embedded and external sessions. External mode writes <code>promptcredentialonce</code>.</p><h3 id="gatewaycredssource-gatewaycredentialsource-↗" tabindex="-1"><code>GatewayCredsSource</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-connection-gatewaycredentialsource">GatewayCredentialSource</a>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings-gatewaycredssource" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewaycredssource-gatewaycredentialsource-↗" aria-label="Permalink to “GatewayCredsSource (GatewayCredentialSource) ↗”">​</a></h3><p>Specifies or retrieves the Remote Desktop Gateway (RD Gateway) authentication method. Support: embedded and external sessions. External mode writes <code>gatewaycredentialssource</code>.</p><h3 id="gatewaydomain-string-↗" tabindex="-1"><code>GatewayDomain</code> (<code>string</code>?) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings2-gatewaydomain" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewaydomain-string-↗" aria-label="Permalink to “GatewayDomain (string?) ↗”">​</a></h3><p>Specifies or retrieves the domain name of a user that is provided to the Remote Desktop Gateway (RD Gateway) server. Support: embedded and external sessions. External mode writes <code>gatewaydomain</code>.</p><h3 id="gatewayhostname-string-↗" tabindex="-1"><code>GatewayHostname</code> (<code>string</code>?) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings-gatewayhostname" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewayhostname-string-↗" aria-label="Permalink to “GatewayHostname (string?) ↗”">​</a></h3><p>Specifies the host name of the Remote Desktop Gateway (RD Gateway) server. Support: embedded and external sessions. External mode writes <code>gatewayhostname</code>.</p><h3 id="gatewaypassword-sensitivestring-↗" tabindex="-1"><code>GatewayPassword</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-sensitivestring">SensitiveString</a>?) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings2-gatewaypassword" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewaypassword-sensitivestring-↗" aria-label="Permalink to “GatewayPassword (SensitiveString?) ↗”">​</a></h3><p>Specifies the password that is used to authenticate to the Remote Desktop Gateway (RD Gateway) server. Support: embedded sessions directly. External mode does not serialize the password into the generated <code>.rdp</code> file, but can stage it in Windows Credential Manager when credential manager integration is enabled.</p><h3 id="gatewayprofileusagemethod-gatewayprofileusagemethod-↗" tabindex="-1"><code>GatewayProfileUsageMethod</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-connection-gatewayprofileusagemethod">GatewayProfileUsageMethod</a>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings-gatewayprofileusagemethod" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewayprofileusagemethod-gatewayprofileusagemethod-↗" aria-label="Permalink to “GatewayProfileUsageMethod (GatewayProfileUsageMethod) ↗”">​</a></h3><p>Specifies whether to use default Remote Desktop Gateway (RD Gateway) settings. Support: embedded and external sessions. External mode writes <code>gatewayprofileusagemethod</code>.</p><h3 id="gatewayusagemethod-gatewayusagemethod-↗" tabindex="-1"><code>GatewayUsageMethod</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-connection-gatewayusagemethod">GatewayUsageMethod</a>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings-gatewayusagemethod" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewayusagemethod-gatewayusagemethod-↗" aria-label="Permalink to “GatewayUsageMethod (GatewayUsageMethod) ↗”">​</a></h3><p>Specifies when to use a Remote Desktop Gateway (RD Gateway) server. Support: embedded and external sessions. External mode writes <code>gatewayusagemethod</code>.</p><h3 id="gatewayusername-string-↗" tabindex="-1"><code>GatewayUsername</code> (<code>string</code>?) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings2-gatewayusername" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewayusername-string-↗" aria-label="Permalink to “GatewayUsername (string?) ↗”">​</a></h3><p>Specifies or retrieves the user name that is provided to the Remote Desktop Gateway (RD Gateway) server. Support: embedded and external sessions. External mode writes <code>gatewayusername</code>.</p><h3 id="gatewayuserselectedcredssource-gatewaycredentialsource-↗" tabindex="-1"><code>GatewayUserSelectedCredsSource</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-connection-gatewaycredentialsource">GatewayCredentialSource</a>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings-gatewayuserselectedcredssource" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewayuserselectedcredssource-gatewaycredentialsource-↗" aria-label="Permalink to “GatewayUserSelectedCredsSource (GatewayCredentialSource) ↗”">​</a></h3><p>Sets or retrieves the user-specified Remote Desktop Gateway (RD Gateway) credential source. Support: embedded and external sessions. External mode writes <code>gatewayuserselectedcredentialssource</code>.</p><p><a href="./../">Back to API index</a></p>',24)])])}const w=a(s,[["render",n]]);export{h as __pageData,w as default};
